import{_ as a,o as r,c as l,ai as t}from"./chunks/framework.CaiDwmc7.js";const p=JSON.parse('{"title":"01 为什么需要中台：从“模型乱搜”到“数据可控”","description":"","frontmatter":{},"headers":[],"relativePath":"ai/stage-3-mvp-server/01-why-mvp-server.md","filePath":"ai/stage-3-mvp-server/01-why-mvp-server.md"}'),i={name:"ai/stage-3-mvp-server/01-why-mvp-server.md"};function s(o,e,n,d,_,c){return r(),l("div",null,[...e[0]||(e[0]=[t('<h1 id="_01-为什么需要中台-从-模型乱搜-到-数据可控" tabindex="-1">01 为什么需要中台：从“模型乱搜”到“数据可控” <a class="header-anchor" href="#_01-为什么需要中台-从-模型乱搜-到-数据可控" aria-label="Permalink to “01 为什么需要中台：从“模型乱搜”到“数据可控””">​</a></h1><blockquote><p>目标：理解这一阶段的意义：<strong>让模型基于你“整理过的上下文”输出，而不是随机抓取/胡乱联想</strong>。</p></blockquote><h2 id="_1-没有中台的典型问题" tabindex="-1">1）没有中台的典型问题 <a class="header-anchor" href="#_1-没有中台的典型问题" aria-label="Permalink to “1）没有中台的典型问题”">​</a></h2><ul><li>上下文不稳定：同一问题多次回答差异大</li><li>数据不可追溯：你不知道它依据了哪段材料</li><li>成本不可控：频繁调用外部 API + LLM</li></ul><h2 id="_2-mvp-server-做什么-一句话" tabindex="-1">2）MVP Server 做什么（一句话） <a class="header-anchor" href="#_2-mvp-server-做什么-一句话" aria-label="Permalink to “2）MVP Server 做什么（一句话）”">​</a></h2><p>把复杂数据源变成统一接口：</p><ul><li>你控制“数据从哪来、长什么样、怎么更新”</li><li>Agent 只负责“拿到干净数据 → 调模型生成结果”</li></ul><h2 id="_3-你最适合的中台场景" tabindex="-1">3）你最适合的中台场景 <a class="header-anchor" href="#_3-你最适合的中台场景" aria-label="Permalink to “3）你最适合的中台场景”">​</a></h2><p>围绕你这套 VitePress 知识库：</p><ul><li>接入：扫描 <code>docs/</code>，抽取标题/小节/标签/摘要</li><li>输出：<code>/context?module=database</code> 返回相关内容片段（结构化）</li></ul>',10)])])}const m=a(i,[["render",s]]);export{p as __pageData,m as default};
